scriptValidator:
const schema = $mv.object({
  event: $mv.object({
    eventId: $mv.string().required(),
    targetName: $mv.string().required(),
    eventType: $mv.string().required(),
    data: $mv.object().required(),
    timestamp: $mv.string().required()
  }).required(),
  labels: $mv.object({
    name: $mv.string().required()
  }).required(),
  metadata: $mv.object({
    deviceId: $mv.string().required(),
    projectId: $mv.string().required(),
    deviceType: $mv.string().required(),
    productNumber: $mv.string().optional()
  }).required()
}).required();

const { value, error } = schema.validate(payload, { abortEarly: false, stripUnknown: true });
if (error) throw new Error('Validation failed: ' + error.message);
const result = { ...value, _validated: true, _validationTimestamp: Date.now() };

scriptConversion:
const result = {
  eventType: payload.event.eventType,
  eventId: payload.event.eventId,
  data: {},
  metadata: {
    deviceId: payload.metadata.deviceId,
    projectId: payload.metadata.projectId,
    deviceType: payload.metadata.deviceType,
    productNumber: payload.metadata.productNumber,
    deviceName: payload.labels.name,
    targetName: payload.event.targetName
  },
  created: new Date().toISOString(),
  originalTimestamp: payload.event.timestamp
};

  if (payload.event.eventType === 'touch') {
    result.data = {
      updateTime: payload.event.data.touch?.updateTime
    };
  } else   if (payload.event.eventType === 'connectionStatus') {
    result.data = {
      connection: payload.event.data.connectionStatus?.connection,
      available: payload.event.data.connectionStatus?.available,
      updateTime: payload.event.data.connectionStatus?.updateTime
    };
  } else   if (payload.event.eventType === 'networkStatus') {
    result.data = {
      signalStrength: payload.event.data.networkStatus?.signalStrength,
      rssi: payload.event.data.networkStatus?.rssi,
      updateTime: payload.event.data.networkStatus?.updateTime,
      cloudConnectors: payload.event.data.networkStatus?.cloudConnectors
    };
  } else   if (payload.event.eventType === 'batteryStatus') {
    result.data = {
      percentage: payload.event.data.batteryStatus?.percentage,
      updateTime: payload.event.data.batteryStatus?.updateTime
    };
  } else   if (payload.event.eventType === 'humidity') {
    result.data = {
      temperature: payload.event.data.humidity?.temperature,
      relativeHumidity: payload.event.data.humidity?.relativeHumidity,
      updateTime: payload.event.data.humidity?.updateTime,
      samples: payload.event.data.humidity?.samples
    };
  }
